var e=JSON.parse(`[{"id":"idx_0","type":"subtitle","speaker":null,"text":{"KOREA":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No. CSM002M000537-49: <color=#ffd34c>에블린 워커</color>","JPN":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No. CSM002M000537-49: <color=#ffd34c>イーヴリンウォーカー</color>","ENG":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No. CSM002M000537-49: <color=#ffd34c>Evelyn Walker</color>","TWN":"(TWN)NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No. CSM002M000537-49: <color=#ffd34c>에블린 워커</color>"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"잘 지내셨습니까, ████ 대행. 관찰대상 관련으로 보고드릴 일이 있습니다.","JPN":"元気でしたか、████代行。観察対象関連でご報告申し上げる事があります。","ENG":"Hope you've been well, Acting Director ████. I have a report regarding the surveillance target.","TWN":"(TWN)잘 지내셨습니까, ████ 대행. 관찰대상 관련으로 보고드릴 일이 있습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_2","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네 목소리를 들으니 반갑군.\\n이번엔 또 누구인가?","JPN":"君声をきくから嬉しいね。\\n今回はまた誰か?","ENG":"Good to hear your voice.\\nWho is it this time?","TWN":"(TWN)자네 목소리를 들으니 반갑군.\\n이번엔 또 누구인가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"idx_3","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"라이언 페리어, 만 56세.\\n신장 187.3cm. 체중 85.1kg.","JPN":"ライアン・フェリエー、満56歳。\\n身長187.3cm.体重85.1kg.","ENG":"Ryan Ferrier, age 56.\\nHeight 187.3cm. Weight 85.1kg.","TWN":"(TWN)라이언 페리어, 만 56세.\\n신장 187.3cm. 체중 85.1kg."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_4","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"런던 출신으로, 대환류 이후 줄곧 프리드웬 기관에서 활동해 온 베테랑 카운터입니다.","JPN":"ロンドン出身で、大患類以後ずっとプリドウェン機関で活動してきたベテランカウンターです。","ENG":"A veteran Counter from London who has been active with the Friedwen Agency since the Great Exchange.","TWN":"(TWN)런던 출신으로, 대환류 이후 줄곧 프리드웬 기관에서 활동해 온 베테랑 카운터입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_5","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"현 관리국 측정 기준 등급은 B급입니다.","JPN":"現管理局測定基準等級はB級です。","ENG":"His current rating under Administration Bureau standards is B-Class.","TWN":"(TWN)현 관리국 측정 기준 등급은 B급입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_6","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"B급이라....... 최전선에서도 믿을 수 있는 수준이군.","JPN":"B級でありなさい.......最前線でも信じることができる水準だね。","ENG":"B-Class, hm....... Reliable enough even for the front lines.","TWN":"(TWN)B급이라....... 최전선에서도 믿을 수 있는 수준이군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_7","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"옛날 기준으로는 그렇죠.\\n하지만 현 채굴업계에선 충분히 유능한 인재입니다.","JPN":"昔基準ではそうです。\\nしかし現採掘業界では十分に有能な人材です。","ENG":"By old standards, yes.\\nBut he's more than capable enough for today's mining industry.","TWN":"(TWN)옛날 기준으로는 그렇죠.\\n하지만 현 채굴업계에선 충분히 유능한 인재입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_8","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"흐음. 자네가 내 식견이나 평하자고 얘기를 꺼내진 않았겠지.","JPN":"フウム。君が私の識見も批評しようと話を持ち出さなかったでしょう。","ENG":"Hmph. I suppose you didn't bring this up to critique my judgment.","TWN":"(TWN)흐음. 자네가 내 식견이나 평하자고 얘기를 꺼내진 않았겠지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_9","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"물론입니다. 자신이 구시대적인 건 잘 알고 계시니까요.","JPN":"もちろんです。自分が旧時代的なことはよくご存じであるからです。","ENG":"Of course not. You're well aware how old-fashioned you are.","TWN":"(TWN)물론입니다. 자신이 구시대적인 건 잘 알고 계시니까요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_10","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......겸허하게 인정하기로 하지.","JPN":"......謙虚に認めることにする。","ENG":"......I'll humbly acknowledge that.","TWN":"(TWN)......겸허하게 인정하기로 하지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_11","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"감사합니다.\\n이번에 보고드린 까닭은 프리드웬 기관이 전면적인 개편을 시작했기 때문입니다.","JPN":"ありがとうございます。\\n今回ご報告申し上げた理由はプリドウェン機関が全面的な改変を始めたからです。","ENG":"Thank you.\\nThe reason I'm reporting this is that the Friedwen Agency has begun a comprehensive restructuring.","TWN":"(TWN)감사합니다.\\n이번에 보고드린 까닭은 프리드웬 기관이 전면적인 개편을 시작했기 때문입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_12","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"대환류 이후 사실상 폐쇄된 것 아니었나?\\n규모로는 영세 태스크포스 수준일 텐데?","JPN":"大患類以後事実上閉鎖されたことではなかったか?\\n規模では零細タスクフォース水準であるでしょうに?","ENG":"Wasn't it practically shut down after the Great Exchange?\\nJust a small-scale task force?","TWN":"(TWN)대환류 이후 사실상 폐쇄된 것 아니었나?\\n규모로는 영세 태스크포스 수준일 텐데?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_13","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이번 신임 기관장이 쇄신을 추진 중입니다.\\n전체적으로 변동 사항이 많아져서 일괄적인 정보 갱신을 계획했습니다.","JPN":"今回新任機関長が刷新を湿っぽくいます。\\n全体的に変動事項が多くなって一括的な情報更新を計画しました。","ENG":"The new Director is pushing for reforms.\\nWith so many changes across the board, we're planning a comprehensive information update.","TWN":"(TWN)이번 신임 기관장이 쇄신을 추진 중입니다.\\n전체적으로 변동 사항이 많아져서 일괄적인 정보 갱신을 계획했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_14","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"알겠네. 조사를 허락하지.\\n하지만 지나치게 깊이 들어가다가 덧나게 하진 말게.","JPN":"分かるのね。調査を承諾する。\\nしかしあまりにも深く入って来て咎めさせないように。","ENG":"Very well. I approve the investigation.\\nBut don't dig too deep and stir up trouble.","TWN":"(TWN)알겠네. 조사를 허락하지.\\n하지만 지나치게 깊이 들어가다가 덧나게 하진 말게."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"idx_15","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 1차 조사 결과는 데이터베이스로 전송했습니다.\\n참고가 되길 바랍니다.","JPN":"はい。１次調査結果はデータベースに転送しました。\\n参考になってほしいです。","ENG":"Yes. I've transmitted the preliminary investigation results to the database.\\nI hope they serve as a useful reference.","TWN":"(TWN)네. 1차 조사 결과는 데이터베이스로 전송했습니다.\\n참고가 되길 바랍니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}}]`);export{e as default};